// InertialCarousel.tsx
import React from 'react';
import {StyleSheet, View, useWindowDimensions} from 'react-native';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import Animated, {useSharedValue, useAnimatedStyle, withDecay, withSpring} from 'react-native-reanimated';
export function InertialCarousel({items, itemWidth}: {items: React.ReactNode[]; itemWidth: number}) {
  const x = useSharedValue(0); const ctx = useSharedValue(0);
  const pan = Gesture.Pan().onStart(() => { ctx.value = x.value; }).onUpdate(e => { x.value = ctx.value + e.translationX; }).onEnd(e => { x.value = withDecay({velocity: e.velocityX, clamp: [-(items.length-1)*itemWidth, 0]}, () => { const snap = Math.round(x.value / itemWidth) * itemWidth; x.value = withSpring(snap, {damping: 20, stiffness: 240}); }); });
  const style = useAnimatedStyle(() => ({transform: [{translateX: x.value}]}));
  return (<GestureDetector gesture={pan}><Animated.View style={[{flexDirection: 'row'}, style]}>{items.map((it, i) => <View key={i} style={{width: itemWidth}}>{it}</View>)}</Animated.View></GestureDetector>);
}

