import React, {useRef, useState} from 'react';
import {StyleSheet, View} from 'react-native';
import {Canvas, Path, Skia, SkPath} from '@shopify/react-native-skia';
import {GestureDetector, Gesture} from 'react-native-gesture-handler';
import {runOnJS} from 'react-native-reanimated';
export function SmoothPad() {
  const [paths, setPaths] = useState<SkPath[]>([]);
  const currentRef = useRef<SkPath | null>(null);
  const lastPoint = useRef<{x: number; y: number} | null>(null);
  const start = (x: number, y: number) => { const p = Skia.Path.Make(); p.moveTo(x, y); currentRef.current = p; lastPoint.current = {x, y}; };
  const append = (x: number, y: number) => { const c = currentRef.current; if (c && lastPoint.current) { const mx = (lastPoint.current.x + x) / 2; const my = (lastPoint.current.y + y) / 2; c.quadTo(lastPoint.current.x, lastPoint.current.y, mx, my); } lastPoint.current = {x, y}; setPaths(ps => [...ps]); };
  const finish = () => { if (currentRef.current) setPaths(ps => [...ps, currentRef.current!]); currentRef.current = null; lastPoint.current = null; };
  const pan = Gesture.Pan().onStart(e => runOnJS(start)(e.x, e.y)).onUpdate(e => runOnJS(append)(e.x, e.y)).onEnd(() => runOnJS(finish)());
  return (<GestureDetector gesture={pan}><View style={{flex:1, backgroundColor:'#000'}}><Canvas style={StyleSheet.absoluteFill}>{paths.map((p, i) => <Path key={i} path={p} style='stroke' strokeWidth={3} color='#fff'/>)}{currentRef.current && <Path path={currentRef.current} style='stroke' strokeWidth={3} color='#fff'/>}</Canvas></View></GestureDetector>);
}

