// SwellingDots.tsx
import React from 'react';
import {StyleSheet, View} from 'react-native';
import Animated, {useAnimatedStyle, useDerivedValue, interpolate, Extrapolation} from 'react-native-reanimated';
export function SwellingDots({count, progress}: {count: number; progress: Animated.SharedValue<number>}) { return (<View style={s.row}>{Array.from({length: count}).map((_, i) => <Dot key={i} index={i} progress={progress}/>)}</View>); }
function Dot({index, progress}: {index: number; progress: Animated.SharedValue<number>}) { const style = useAnimatedStyle(() => { const dist = Math.abs(progress.value - index); return {transform: [{scale: interpolate(dist, [0, 0.5, 1], [1.5, 1.1, 1], Extrapolation.CLAMP)}]}; }); return <Animated.View style={[s.dot, style]}/>; }
