import React from 'react';
import {StyleSheet, useWindowDimensions} from 'react-native';
import {Canvas, Circle, BlurMask} from '@shopify/react-native-skia';
import {useSharedValue, useFrameCallback, useDerivedValue} from 'react-native-reanimated';
export function BokehBg() { const {width: SW, height: SH} = useWindowDimensions(); const t = useSharedValue(0); useFrameCallback(({timeSinceFirstFrame}) => { t.value = timeSinceFirstFrame / 1000; }); const circles = Array.from({length: 6}).map((_, i) => ({cx: useDerivedValue(() => (SW/6) * i + Math.sin(t.value * 0.1 + i) * 40), cy: useDerivedValue(() => SH/2 + Math.cos(t.value * 0.1 + i * 1.3) * 80), r: 40 + i * 6})); return (<Canvas style={StyleSheet.absoluteFill}>{circles.map((c, i) => <Circle key={i} cx={c.cx} cy={c.cy} r={c.r} color='rgba(255,255,255,0.1)'><BlurMask blur={20} style='normal'/></Circle>)}</Canvas>); }

