import React from 'react';
import {StyleSheet, View, Pressable, Text} from 'react-native';
import * as Haptics from 'expo-haptics';
export function Stepper({value, onChange, min = 0, max = 99}: {value: number; onChange: (v: number) => void; min?: number; max?: number}) { const set = (v: number) => { Haptics.selectionAsync(); onChange(Math.max(min, Math.min(max, v))); }; return (<View style={s.row}><Pressable hitSlop={10} onPress={() => set(value - 1)} disabled={value <= min} style={[s.btn, value <= min && s.disabled]}><Text style={s.text}>−</Text></Pressable><Text style={s.value}>{value}</Text><Pressable hitSlop={10} onPress={() => set(value + 1)} disabled={value >= max} style={[s.btn, value >= max && s.disabled]}><Text style={s.text}>+</Text></Pressable></View>); }
